import React from 'react';
import './county-transition.css'
class CountyTransitiont extends React.Component {
	handleCloseBattle = () => {
	    console.log("Closing battle"); // Add this line
	// Call the function passed from the parent component
    if (this.props.onCloseBattle) {
		this.props.onCloseBattle();
	  }
};


  render() {
    return (
      <div className="county-transition">
        <h2>Battle Mode</h2>
        {/* Add your battle UI and logic here */}
        <button onClick={this.handleCloseBattle}>Close Battle</button>
      </div>
    );
  }
}

export default CountyTransition;
